content:
{
  "sentences": [
    {
      "text": "我想約朋友一起去喝咖啡。",
      "pinyin": "Wǒ xiǎng yuē péngyǒu yīqǐ qù hē kāfēi.",
      "pinyin_numeric": "wo3 xiang3 yue1 peng2you3 yi1qi3 qu4 he1 ka1fei1.",
      "translation_en": "I want to invite a friend to go drink coffee together.",
      "translation_ko": "친구랑 같이 커피 마시러 가고 싶어요."
    },
    {
      "text": "你想約誰一起去吃飯？",
      "pinyin": "Nǐ xiǎng yuē shéi yīqǐ qù chīfàn?",
      "pinyin_numeric": "ni3 xiang3 yue1 shei2 yi1qi3 qu4 chi1fan4?",
      "translation_en": "Who do you want to invite to go eat together?",
      "translation_ko": "누구랑 같이 밥 먹으러 가고 싶어요?"
    },
    {
      "text": "他不想看電影，他想去逛街。",
      "pinyin": "Tā bù xiǎng kàn diànyǐng, tā xiǎng qù guàngjiē.",
      "pinyin_numeric": "ta1 bu4 xiang3 kan4 dian4ying3, ta1 xiang3 qu4 guang4jie1.",
      "translation_en": "He doesn't want to watch a movie; he wants to go shopping.",
      "translation_ko": "그는 영화 보기 싫어하고, 쇼핑 가고 싶어해요."
    },
    {
      "text": "我們想約時間一起聊天。",
      "pinyin": "Wǒmen xiǎng yuē shíjiān yīqǐ liáotiān.",
      "pinyin_numeric": "wo3men xiang3 yue1 shi2jian1 yi1qi3 liao2tian1.",
      "translation_en": "We want to arrange a time to chat together.",
      "translation_ko": "우리는 시간을 정해서 같이 이야기하고 싶어요."
    },
    {
      "text": "你想約在哪裡見面？",
      "pinyin": "Nǐ xiǎng yuē zài nǎlǐ jiànmiàn?",
      "pinyin_numeric": "ni3 xiang3 yue1 zai4 na3li3 jian4mian4?",
      "translation_en": "Where do you want to arrange to meet?",
      "translation_ko": "어디서 만나기로 하고 싶어요?"
    },
    {
      "text": "她不想去咖啡店，她想去餐廳吃飯。",
      "pinyin": "Tā bù xiǎng qù kāfēidiàn, tā xiǎng qù cāntīng chīfàn.",
      "pinyin_numeric": "ta1 bu4 xiang3 qu4 ka1fei1dian4, ta1 xiang3 qu4 can1ting1 chi1fan4.",
      "translation_en": "She doesn't want to go to a coffee shop; she wants to go to a restaurant to eat.",
      "translation_ko": "그녀는 카페에 가기 싫어하고, 식당에 가서 밥 먹고 싶어해요."
    },
    {
      "text": "我想約你一起去逛街，你有空嗎？",
      "pinyin": "Wǒ xiǎng yuē nǐ yīqǐ qù guàngjiē, nǐ yǒu kòng ma?",
      "pinyin_numeric": "wo3 xiang3 yue1 ni3 yi1qi3 qu4 guang4jie1, ni3 you3 kong4 ma0?",
      "translation_en": "I want to invite you to go shopping together; are you free?",
      "translation_ko": "같이 쇼핑 가고 싶은데, 시간 있어요?"
    },
    {
      "text": "我們想約下個星期一起去吃飯。",
      "pinyin": "Wǒmen xiǎng yuē xià ge xīngqī yīqǐ qù chīfàn.",
      "pinyin_numeric": "wo3men xiang3 yue1 xia4 ge4 xing1qi1 yi1qi3 qu4 chi1fan4.",
      "translation_en": "We want to arrange to go eat together next week.",
      "translation_ko": "우리는 다음 주에 같이 밥 먹으러 가기로 하고 싶어요."
    },
    {
      "text": "你想約誰一起去喝咖啡？",
      "pinyin": "Nǐ xiǎng yuē shéi yīqǐ qù hē kāfēi?",
      "pinyin_numeric": "ni3 xiang3 yue1 shei2 yi1qi3 qu4 he1 ka1fei1?",
      "translation_en": "Who do you want to invite to go drink coffee together?",
      "translation_ko": "누구랑 같이 커피 마시러 가고 싶어요?"
    },
    {
      "text": "他不想去逛街，他想在家看電影。",
      "pinyin": "Tā bù xiǎng qù guàngjiē, tā xiǎng zài jiā kàn diànyǐng.",
      "pinyin_numeric": "ta1 bu4 xiang3 qu4 guang4jie1, ta1 xiang3 zai4 jia1 kan4 dian4ying3.",
      "translation_en": "He doesn't want to go shopping; he wants to watch a movie at home.",
      "translation_ko": "그는 쇼핑 가기 싫어하고, 집에서 영화 보고 싶어해요."
    }
  ]
}
